const fetchBook = async () => {
    console.log("[READER] Cache Check for:", book.path);
    try {
        setLoading(true);
        const db = await getDB();

        // 1. Check Cache with Versioning
        const cacheKey = `${CACHE_VERSION}_${book.path}`;
        const cachedBlob = await new Promise((resolve) => {
            const transaction = db.transaction(STORE_NAME, "readonly");
            const request = transaction.objectStore(STORE_NAME).get(cacheKey);
            request.onsuccess = () => resolve(request.result);
        });

        if (cachedBlob) {
            console.log(`[READER] Serving version ${CACHE_VERSION} from Local Storage`);
            setIframeSrc(URL.createObjectURL(cachedBlob));
            setLoading(false);
            return;
        }

        // 2. Network Fallback
        console.log("[READER] Cache Miss. Fetching from Network...");
        const response = await fetch('https://xvldfsmxskhemkslsbym.supabase.co/functions/v1/book-reader', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ 
                action: 'get_book_compressed',
                book_path: book.path
            })
        });

        if (!response.ok) throw new Error("Failed to fetch book");

        const blob = await response.blob();

        // 3. Save to Cache for next time
        const cacheKey = `${CACHE_VERSION}_${book.path}`;
        const saveTx = db.transaction(STORE_NAME, "readwrite");
        saveTx.objectStore(STORE_NAME).put(blob, cacheKey);

