import { serve } from "https://deno.land/std@0.168.0/http/server.ts";
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';

const GITHUB_PAT = Deno.env.get("GITHUB_PAT");
const REPO_OWNER = "GetyeTek";
const REPO_NAME = "LinkUp";
const BRANCH = "main";
const PUBLIC_ENDPOINT = "https://xvldfsmxskhemkslsbym.supabase.co/functions/v1/book-reader";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers": "authorization, x-client-info, apikey, content-type, accept-encoding",
};

serve(async (req) => {
  if (req.method === "OPTIONS") return new Response("ok", { headers: corsHeaders });

  const url = new URL(req.url);

  if (req.method === "GET") {
    const action = url.searchParams.get("action");
    const path = url.searchParams.get("path");
    if (action === "proxy_image" && path) {
      try {
        const rawUrl = `https://raw.githubusercontent.com/${REPO_OWNER}/${REPO_NAME}/${BRANCH}/${path}`;
        const imgResp = await fetch(rawUrl, { headers: { "Authorization": `token ${GITHUB_PAT}` } });
        const blob = await imgResp.blob();
        return new Response(blob, { headers: { ...corsHeaders, "Content-Type": imgResp.headers.get("Content-Type") || "image/jpeg" } });
      } catch (e) { return new Response("Proxy Error", { status: 500 }); }
    }
  }

  try {
    const body = await req.json();
    const { action, book_path, university_id } = body;
    console.log(`[START] Action: ${action} | Target: ${book_path || university_id}`);

    const supabase = createClient(Deno.env.get('SUPABASE_URL')!, Deno.env.get('SUPABASE_SERVICE_ROLE_KEY')!);

    if (action === "list_books") {
       const treeUrl = `https://api.github.com/repos/${REPO_OWNER}/${REPO_NAME}/git/trees/${BRANCH}?recursive=1`;
       const resp = await fetch(treeUrl, { headers: { "Authorization": `token ${GITHUB_PAT}` } });
       const data = await resp.json();
       const folderMap = new Map();
       for (const item of data.tree || []) {
         if (!item.path.startsWith("Books/") || item.type !== "blob") continue;
         const parts = item.path.split("/");
         const folder = parts.slice(0, -1).join("/");
         if (!folderMap.has(folder)) folderMap.set(folder, {});
         const entry = folderMap.get(folder);
         if (item.path.endsWith(".html")) entry.html = item;
         else if (/\.(jpg|jpeg|png|webp)$/i.test(item.path)) entry.image = item.path;
       }
       const books = [];
       for (const [_, fData] of folderMap) {
         if (fData.html) {
           const filename = fData.html.path.split("/").pop();
           books.push({ 
             path: fData.html.path, 
             title: filename.replace(/\.html$/i, "").replace(/_/g, " "), 
             cover_url: fData.image ? `${PUBLIC_ENDPOINT}?action=proxy_image&path=${encodeURIComponent(fData.image)}` : null 
           });
         }
       }
       return new Response(JSON.stringify({ books }), { headers: { ...corsHeaders, "Content-Type": "application/json" } });
    }

    if (action === "list_universities") {
      const { data: universities, error } = await supabase.from('universities').select('*').order('name', { ascending: true });
      if (error) throw error;
      const universityBooks = universities.map(uni => ({ id: uni.id, title: uni.name, name: uni.name, short_name: uni.short_name, cover_url: null }));
      return new Response(JSON.stringify({ universities: universityBooks }), { headers: { ...corsHeaders, "Content-Type": "application/json" } });
    }

    if (action === "list_exams") {
      const { data, error } = await supabase.from('exams').select('id, exam_type, date, time_allowed_minutes, total_marks, courses (code, name)').eq('university_id', university_id).order('created_at', { ascending: false });
      if (error) throw error;
      const mappedExams = data.map(exam => ({ ...exam, course_name: exam.courses?.name || 'General Assessment', course_code: exam.courses?.code || 'EXAM' }));
      return new Response(JSON.stringify({ exams: mappedExams }), { headers: { ...corsHeaders, "Content-Type": "application/json" } });
    }

    if (action === "get_exam_questions") {
      const { exam_id } = body;
      const [sectionsResp, metaResp] = await Promise.all([
        supabase.from('sections').select('*, questions (*)').eq('exam_id', exam_id).order('section_order', { ascending: true }),
        supabase.from('exams').select('courses(name, code)').eq('id', exam_id).single()
      ]);
      if (sectionsResp.error) throw sectionsResp.error;
      return new Response(JSON.stringify({ sections: sectionsResp.data, course_name: metaResp.data?.courses?.name || 'General Assessment', course_code: metaResp.data?.courses?.code || 'EXAM' }), { headers: { ...corsHeaders, "Content-Type": "application/json" } });
    }

    if (action === "get_book_compressed") {
      const rawUrl = `https://raw.githubusercontent.com/${REPO_OWNER}/${REPO_NAME}/${BRANCH}/${book_path}`;
      const resp = await fetch(rawUrl, { headers: { "Authorization": `token ${GITHUB_PAT}` } });
      let html = await resp.text();
      console.log(`[DIAGNOSTIC] Book Loaded: ${html.length} chars`);

      const baseName = book_path.split('/').pop().replace(/\.[^/.]+$/, ""); 
      const { data: doc } = await supabase.from('documents').select('id, file_name').ilike('file_name', `%${baseName}%`).limit(1).single();

      if (doc) {
        console.log(`[DOC_MATCH] Linked to DB ID: ${doc.id}`);
        const { data: questions } = await supabase.from('book_question_links').select(`question:questions (*), chunk:chunks!inner (page_number, document_id)`).eq('chunks.document_id', doc.id);

        if (questions && questions.length > 0) {
          console.log(`[DATA] Processing ${questions.length} questions.`);

          const pagesWithQuestions = questions.reduce((acc: any, curr: any) => {
            if (curr.chunk && curr.chunk.page_number) {
              const pg = curr.chunk.page_number;
              if (!acc[pg]) acc[pg] = [];
              acc[pg].push(curr.question);
            }
            return acc;
          }, {});

          const sortedPages = Object.entries(pagesWithQuestions).sort((a, b) => Number(b[0]) - Number(a[0]));

          for (const [pageNum, qList] of sortedPages) {
            console.log(`[SURGERY] Targeting Page ${pageNum}...`);

            // 1. Find the Page Anchor
            const pageMarker = `aria-label="Page ${pageNum}"`;
            const markerIdx = html.indexOf(pageMarker);

            if (markerIdx !== -1) {
              // 2. Find the VERY NEXT text-container after this specific page marker
              const containerTag = 'class="text-container">';
              const containerIdx = html.indexOf(containerTag, markerIdx);

              if (containerIdx !== -1) {
                const insertIdx = containerIdx + containerTag.length;
                const dataPayload = JSON.stringify(qList);
                const injection = `\n<div class="miron-challenge-anchor" data-questions='${dataPayload.replace(/'/g, "&apos;")}'></div>\n`;

                html = html.slice(0, insertIdx) + injection + html.slice(insertIdx);
                console.log(`[SURGERY] SUCCESS: Page ${pageNum} injected into text-container at index ${insertIdx}`);
              } else {
                // Fallback: Just after the aria-label div opens
                const endOfMarker = html.indexOf('>', markerIdx) + 1;
                const injection = `<div class="miron-challenge-anchor" data-questions='${JSON.stringify(qList).replace(/'/g, "&apos;")}'></div>`;
                html = html.slice(0, endOfMarker) + injection + html.slice(endOfMarker);
                console.log(`[SURGERY] FALLBACK: Page ${pageNum} injected at marker end (no container found)`);
              }
            } else {
              console.warn(`[SURGERY] FAILED: Page marker ${pageNum} not found in HTML string.`);
            }
          }
        } else {
          console.log("[DATA] No questions linked to this document.");
        }
      } else {
        console.warn(`[DOC_MATCH] No DB document found for: ${baseName}`);
      }

      return new Response(html, { headers: { ...corsHeaders, "Content-Type": "text/html; charset=utf-8" } });
    }

    throw new Error(`Unknown action: ${action}`);
  } catch (error) {
    console.error(`[FATAL] ${error.message}`);
    return new Response(JSON.stringify({ error: error.message }), { status: 500, headers: corsHeaders });
  }
});

