/* 1. MASKING STRATEGY: Hide PDF text behind the question */
.miron-portal-container {
    position: relative !important;
    display: block !important;
    z-index: 1000 !important; /* Above page overlays */
    width: 90% !important;
    margin: 60px auto !important;
    pointer-events: auto !important;
    background-color: #0c0c0c !important; 
    border-radius: 20px;
    box-shadow: 0 0 0 2000px #0c0c0c; /* Infinite mask effect */
    clip-path: inset(-100px -2000px -100px -2000px);
}

.miron-question-card {
    background: #0f0f0f !important;
    border: 2px solid rgba(66, 215, 184, 0.3) !important;
    border-radius: 20px !important;
    padding: 2.5rem 2rem !important;
    display: flex;
    flex-direction: column;
    gap: 1.5rem;
    position: relative;
    box-shadow: 0 10px 40px rgba(0,0,0,0.8) !important;
}

