    });

    const getDB = () => new Promise((resolve, reject) => {
        const request = indexedDB.open(DB_NAME, 1);
        request.onupgradeneeded = () => request.result.createObjectStore(STORE_NAME);
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
    });

    useEffect(() => {
        const fetchBook = async () => {
            const cacheKey = `${CACHE_VERSION}_${book.path}`;
            try {
                setLoading(true);
                const db = await getDB();
                const cachedBlob = await new Promise((resolve) => {
                    const transaction = db.transaction(STORE_NAME, "readonly");
                    const request = transaction.objectStore(STORE_NAME).get(cacheKey);
                    request.onsuccess = () => resolve(request.result);
                });

                if (cachedBlob) {
                    setIframeSrc(URL.createObjectURL(cachedBlob));
                    setLoading(false);
                    return;
                }

                const response = await fetch('https://xvldfsmxskhemkslsbym.supabase.co/functions/v1/book-reader', {
                    method: 'POST', 
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ action: 'get_book_compressed', book_path: book.path })
                });
                if (!response.ok) throw new Error("Failed to fetch book");
                const blob = await response.blob();
                const saveTx = db.transaction(STORE_NAME, "readwrite");
                saveTx.objectStore(STORE_NAME).put(blob, cacheKey);
                setIframeSrc(URL.createObjectURL(blob));
            } catch (error) {
                console.error("Error loading book:", error);
                onClose();
            } finally { setLoading(false); }
        };
        if (book?.path) fetchBook();
        return () => { if (iframeSrc) URL.revokeObjectURL(iframeSrc); };
    }, [book]);

    const measureIframe = () => {
        if (!iframeRef.current || !layerRef.current) return;
        const doc = iframeRef.current.contentDocument;
        if (!doc) return;
        const body = doc.body;
        const html = doc.documentElement;
        const w = Math.max(body.scrollWidth, body.offsetWidth, html.clientWidth, html.scrollWidth);
        const h = Math.max(body.scrollHeight, body.offsetHeight, html.clientHeight, html.scrollHeight);

        contentDims.current = { width: w, height: h };
        layerRef.current.style.width = `${w}px`;
        layerRef.current.style.height = `${h}px`;

        const vw = window.innerWidth;
        minScaleLimit.current = vw / w;
        if (!hasMeasured.current) {
            state.current.scale = minScaleLimit.current;
            hasMeasured.current = true;
        }
    };

    useEffect(() => {
        if (portals.length > 0) {
            setTimeout(measureIframe, 600);
        }
    }, [portals]);

    const handleIframeLoad = (e) => {
        const iframe = e.target;
        iframeRef.current = iframe;
        setTimeout(() => {
            try {
                const doc = iframe.contentDocument || iframe.contentWindow.document;
                if (!doc) return;
                const docBody = doc.body;

                const anchors = doc.querySelectorAll('.miron-challenge-anchor');
                const portalData = Array.from(anchors).map((anchor, i) => {
                    const raw = anchor.getAttribute('data-questions');
                    const parentPage = anchor.closest('.page-container');
                    if (parentPage) {
                        parentPage.after(anchor);
                    } else {
                        docBody.appendChild(anchor);
                    }
                    anchor.style.display = 'block';
                    anchor.style.position = 'relative';
                    anchor.style.zIndex = '2147483647';
                    anchor.style.width = '100%';
                    try {
                        return { id: `portal-${i}`, target: anchor, questions: JSON.parse(raw) };
                    } catch(e) { return null; }
                }).filter(Boolean);
                setPortals(portalData);

                const style = doc.createElement('style');
                style.textContent = `
                    body {
                        transition: background-color 0.3s ease, color 0.3s ease;
                        margin: 0; padding: 0 0 600px 0 !important; 
                        -webkit-font-smoothing: antialiased;
                        user-select: none;
                        overflow: visible !important;
                    }
                    .page, .page-container, .text-container, div, section {
                        overflow: visible !important;
                    }
                    body.theme-dark, body.theme-dark div, body.theme-dark p { background-color: #0c0c0c !important; color: #e0e0e0 !important; }
                    .miron-portal-container {
                        position: relative !important;
                        display: block !important;
                        z-index: 999999 !important;
                        width: 90% !important;
                        max-width: 650px !important;
                        min-height: 200px !important;
                        margin: 40px auto !important;
                        background-color: #1a1a1a !important; 
                        border: 2px solid #42d7b8 !important;
                        border-radius: 24px;
                        box-shadow: 0 20px 50px rgba(0,0,0,0.5);
                        pointer-events: auto !important;
                    }
                    .miron-portal-container * { pointer-events: auto !important; }
                `;
                doc.head.appendChild(style);
                doc.body.className = `theme-${currentTheme}`;
                measureIframe();
            } catch (err) { console.error("Iframe Load Error:", err); }
        }, 200);
    };

    const loop = () => {
        if (!input.current.isDragging) {
            const v = velocity.current;
            if (Math.abs(v.x) < 0.5) v.x = 0;
            if (Math.abs(v.y) < 0.5) v.y = 0;
            if (v.x !== 0 || v.y !== 0) {
                v.x *= CONFIG.friction; v.y *= CONFIG.friction;
                state.current.x += v.x; state.current.y += v.y;
            }
        }
        applyConstraints();
        if (layerRef.current) {
            const { x, y, scale } = state.current;
            layerRef.current.style.transform = `translate3d(${x}px, ${y}px, 0) scale(${scale})`;
        }
        if (sliderRef.current && pageCountRef.current && contentDims.current.height > 0) {
            const unscaledTotalH = contentDims.current.height;
            const unscaledY = Math.abs(state.current.y) / state.current.scale;
            const viewHeight = window.innerHeight / state.current.scale;
            const maxScroll = Math.max(1, unscaledTotalH - viewHeight);
            if (!input.current.isSliderDragging) {
                const progress = (unscaledY / maxScroll) * 100;
                sliderRef.current.value = Math.max(0, Math.min(100, progress));
            }
            const bookPageHeight = contentDims.current.width * 1.3;
            const totalPages = Math.max(1, Math.ceil(unscaledTotalH / bookPageHeight));
            const currentPage = Math.min(totalPages, Math.max(1, Math.floor((unscaledY + (bookPageHeight * 0.3)) / bookPageHeight) + 1));
            pageCountRef.current.innerText = `${currentPage}/${totalPages}`;
        }
        requestRef.current = requestAnimationFrame(loop);
    };

    const applyConstraints = () => {
        const vw = window.innerWidth, vh = window.innerHeight;
        const { width, height } = contentDims.current;
        const s = state.current, v = velocity.current;
        const visualW = width * s.scale, visualH = height * s.scale;
        if (visualW < vw) { s.x = (vw - visualW) / 2; v.x = 0; } 
        else { if (s.x > 0) { s.x = 0; v.x = 0; } if (s.x < vw - visualW) { s.x = vw - visualW; v.x = 0; } }
        if (visualH < vh) { s.y = (vh - visualH) / 2; v.y = 0; }
        else { if (s.y > 0) { s.y = 0; v.y = 0; } if (s.y < vh - visualH) { s.y = vh - visualH; v.y = 0; } }
    };

    useEffect(() => {
        const viewport = viewportRef.current;
        if (!viewport) return;
        requestRef.current = requestAnimationFrame(loop);
        const onTouchStart = (e) => {
            if (e.target.closest('#ui-layer') || e.target.closest('.fab-container')) return;
            e.preventDefault();
            const now = Date.now();
            if (now - input.current.lastFlickTime < 600) input.current.boostLevel = Math.min(input.current.boostLevel + 0.8, 5.0);
            else input.current.boostLevel = 1.0;
            velocity.current = { x: 0, y: 0 };
            input.current.dragTotalDistance = 0;
            input.current.touchStartTime = now;
            if (e.touches.length === 1) {
                input.current.isDragging = true;
                input.current.startX = e.touches[0].clientX - state.current.x;
                input.current.startY = e.touches[0].clientY - state.current.y;
                input.current.lastX = e.touches[0].clientX; input.current.lastY = e.touches[0].clientY;
                input.current.lastTime = Date.now();
            } else if (e.touches.length === 2) {
                input.current.isDragging = false;
                input.current.initialPinchDist = Math.hypot(e.touches[0].pageX - e.touches[1].pageX, e.touches[0].pageY - e.touches[1].pageY);
                input.current.initialScale = state.current.scale;
            }
        };
        const onTouchMove = (e) => {
            if (e.target.closest('#ui-layer')) return;
            e.preventDefault();
            if (input.current.isDragging && e.touches.length === 1) {
                const x = e.touches[0].clientX, y = e.touches[0].clientY;
                const dt = Date.now() - input.current.lastTime;
                input.current.dragTotalDistance += Math.hypot(x - input.current.lastX, y - input.current.lastY);
                state.current.x = x - input.current.startX;
                state.current.y = y - input.current.startY;
                if (dt > 0) {
                    velocity.current.x = (x - input.current.lastX) * CONFIG.velocityMult;
                    velocity.current.y = (y - input.current.lastY) * CONFIG.velocityMult;
                }
                input.current.lastX = x; input.current.lastY = y; input.current.lastTime = Date.now();
            } else if (e.touches.length === 2) {
                const dist = Math.hypot(e.touches[0].pageX - e.touches[1].pageX, e.touches[0].pageY - e.touches[1].pageY);
                const cx = (e.touches[0].pageX + e.touches[1].pageX) / 2, cy = (e.touches[0].pageY + e.touches[1].pageY) / 2;
                const ratio = dist / input.current.initialPinchDist;
                let newScale = Math.max(minScaleLimit.current, Math.min(input.current.initialScale * ratio, CONFIG.maxZoom));
                const contentX = (cx - state.current.x) / state.current.scale, contentY = (cy - state.current.y) / state.current.scale;
                state.current.x = cx - (contentX * newScale); state.current.y = cy - (contentY * newScale); state.current.scale = newScale;
            }
        };
        const onTouchEnd = (e) => {
            if (e.target.closest('#ui-layer')) return;
            if (input.current.isDragging && e.touches.length === 0) {
                input.current.isDragging = false;
                const duration = Date.now() - input.current.touchStartTime;
                if (duration < 250 && input.current.dragTotalDistance > 20) {
                    input.current.lastFlickTime = Date.now();
                    velocity.current.x *= input.current.boostLevel; velocity.current.y *= input.current.boostLevel;
                } else { input.current.boostLevel = 1.0; input.current.lastFlickTime = 0; }
            }
        };
        viewport.addEventListener('touchstart', onTouchStart, { passive: false });
        viewport.addEventListener('touchmove', onTouchMove, { passive: false });
        viewport.addEventListener('touchend', onTouchEnd);
        return () => {
            viewport.removeEventListener('touchstart', onTouchStart);
            viewport.removeEventListener('touchmove', onTouchMove);
            viewport.removeEventListener('touchend', onTouchEnd);
            if (requestRef.current) cancelAnimationFrame(requestRef.current);
        };
    }, []);

    return (
        <div className="reader-root">
            <div id="viewport" ref={viewportRef}>
                <div id="book-layer" ref={layerRef}>
                    {iframeSrc && (
                        <iframe id="book-iframe" src={iframeSrc} onLoad={handleIframeLoad} title="Book Content" />
                    )}
                </div>
                {loading && <div className="loading-spinner">Loading Book...</div>}
            </div>

            <div id="main-fab" className={`fab-container ${isUiVisible ? 'active' : ''}`}>
                <div className="fab-options">
                    <div className="fab-mini" data-label="Theme" onClick={() => setCurrentTheme(t => t === 'light' ? 'dark' : 'light')}>Theme</div>
                    <div className="fab-mini" data-label="Reset" onClick={() => { state.current.scale = minScaleLimit.current; state.current.x = 0; state.current.y = 0; }}>Reset</div>
                </div>
                <div className="fab-main" onClick={() => setIsUiVisible(!isUiVisible)}>+</div>
            </div>

            {portals.map(p => ReactDOM.createPortal(<MironPortal id={p.id} questions={p.questions} />, p.target))}

            <div id="ui-layer" className={isUiVisible ? '' : 'hidden'}>
                <div className="ui-bar reader-header">
                    <div className="header-left" onClick={onClose}>Back</div>
                    <div className="header-title">{book?.title}</div>
                </div>
                <div className="ui-bar reader-footer">
                    <div className="slider-container">
                        <input ref={sliderRef} type="range" min="0" max="100" step="0.1" defaultValue="0" onInput={(e) => {
                            const val = parseFloat(e.target.value);
                            const maxScroll = Math.max(1, contentDims.current.height - (window.innerHeight / state.current.scale));
                            state.current.y = -((val / 100) * maxScroll * state.current.scale);
                            velocity.current = { x: 0, y: 0 };
                        }} />
                    </div>
                    <span className="page-count" ref={pageCountRef}>1/--</span>
                </div>
            </div>
        </div>
    );
};

export default BookReader;
